INSERT INTO public."documents" (id,supplier_id,document_type,file_url,file_name,status,version,notes,reviewed_by,reviewed_at,created_at,updated_at,razon_social,representante_legal,objeto_social,registro_publico,extracted_at,extraction_status,rfc,actividad_economica,regimen_tributario,fecha_emision,codigo_postal,direccion,validation_errors,is_valid,nombre_completo_ine,curp,image_urls,numero_cuenta,numero_cuenta_clabe,nombre_cliente,nombre_banco,regimen_fiscal) VALUES ('be010d06-a82a-4812-a590-f75468b68ae4','5590e2d6-b56e-4b38-a4f3-8e59205aab4b','acta_constitutiva','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0.pdf','ACTA-COMERCIALIZADORA ASUAN NORESTE_compressed.pdf','aprobado','1',NULL,'989165e0-c24f-4360-a1dc-1b84536947b5','2026-01-02 16:48:21.37+00','2025-12-31 16:00:11.219621+00','2026-01-02 16:48:21.382639+00','COMERCIALIZADORA ASUAN NORESTE, S. A. DE C. V.','EVERARDO ALANIS GUERRA','La sociedad tiene como objeto la prestación por cuenta propia o de terceros de toda clase de servicios profesionales, la consultoría, planeación, coordinación, administración, ejecución y operación de servicios profesionales y administrativos de todo tipo de empresas, personas físicas o morales, públicas o privadas, nacionales o extranjeras en lo relativo al fomento, desarrollo y ejecución de actividades como análisis económicos, financieros, contables, de ingeniería y mercadotecnia. La sociedad podrá dedicarse a actividades de comercialización, distribución, compraventa, arrendamiento, importación y exportación de toda clase de bienes muebles e inmuebles, materias primas, productos terminados, maquinaria, equipo de transporte, refacciones y accesorios, software, desarrollo de sistemas computacionales y programación. La sociedad también podrá dedicarse a la adquisición, enajenación, administración, explotación y construcción de todo tipo de inmuebles, urbanos, rústicos, agrícolas, ganaderos y de cualquier otra índole, así como al desarrollo de proyectos inmobiliarios. La sociedad podrá realizar la compra, venta, consignación, importación, exportación, distribución, comercio y en general, de toda clase de artículos y productos lícitos, así como la prestación de servicios generales y de consultoría en los ramos de administración, contabilidad, finanzas y mercadotecnia, tales como la planeación, organización, dirección y control empresarial, auditorías contables y administrativas, estudios financieros, valuación de empresas, elaboración de presupuestos, sistemas de información gerencial, estudios de mercado, planes de negocio y asesoría en comercio exterior. La sociedad también podrá dedicarse a la creación, desarrollo, producción, comercialización y administración de empresas; la elaboración de estudios y proyectos en materia ambiental; la explotación de franquicias; así como la formación, capacitación y desarrollo de recursos humanos, entre otros.','Pública de Notaría 96, Nuevo León. Número de documento: 20230027650400J2; Inscripción: 2023-10-23T14:29:13.236-05:00','2025-12-31 16:02:49.746+00','completed',NULL,NULL,NULL,NULL,NULL,NULL,'[]','true',NULL,NULL,'{5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_1.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_2.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_3.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_4.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_5.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_6.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_7.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_8.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_9.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_10.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_11.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/1767196805334_0_page_12.png,5590e2d6-b56e-4b38-a4f3-8e59205aab4b/176719680533