INSERT INTO public."documents" (id,supplier_id,document_type,file_url,file_name,status,version,notes,reviewed_by,reviewed_at,created_at,updated_at,razon_social,representante_legal,objeto_social,registro_publico,extracted_at,extraction_status,rfc,actividad_economica,regimen_tributario,fecha_emision,codigo_postal,direccion,validation_errors,is_valid,nombre_completo_ine,curp,image_urls,numero_cuenta,numero_cuenta_clabe,nombre_cliente,nombre_banco,regimen_fiscal) VALUES ('dedc937d-2e3d-4ffb-8c9c-282d3baa5616','3040f0ae-a60e-4b8c-a1ac-746c13987e41','acta_constitutiva','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/3040f0ae-a60e-4b8c-a1ac-746c13987e41/1769276536341_0.pdf','ACTA CONSTITUTIVA Y AVISO FUNCIONAMIENTO SWISS MEDIC S.A DE C.V..pdf','aprobado','1',NULL,'989165e0-c24f-4360-a1dc-1b84536947b5','2026-02-05 00:48:49.078+00','2026-01-24 17:42:25.721583+00','2026-02-05 00:48:48.865133+00','SWISS MEDIC, SOCIEDAD ANONIMA DE CAPITAL VARIABLE','GERARDO HUERTA MONTES','La compraventa, importación, exportación, almacenamiento, distribución, suministro, representación, agencia, comisión mercantil, mediación, manejo a consignación, la comercialización de bienes y servicios relacionados con la industria de la medicina, tales como medicamentos, medicinas, productos naturistas, suplementos alimenticios, remedios herbolarios, equipos e instrumental médico y hospitalario, materiales y equipos para laboratorios, equipos y materiales de curación, prótesis, equipos de ultrasonido, radiológico, ropa hospitalaria y uniformes, así como de toda clase de bienes, aparatos, productos y accesorios para hospitales y clínicas e instituciones médicas o relacionadas con éstas, sean de carácter público o privado, nacionales y extranjeras; así como la fabricación, manufactura, elaboración, producción, maquila, procesamientos industriales, empaque y embalaje de los mismos. La compraventa, importación, exportación, almacenamiento, distribución, suministro, representación, agencia, comisión mercantil, mediación, manejo a consignación y en general, la comercialización de bienes de producción, materias primas, insumos, productos semi-manufacturados y semi-ensamblados, necesarios para la realización de los procesos industriales o comerciales de la empresa. La proyección, desarrollo, instalación, operación, organización, administración y representación, sea por cuenta propia o de terceros, de fábricas, industrias y comercializadoras de toda clase de bienes y productos relacionados con la industria de la medicina; así como de hospitales, clínicas, laboratorios de análisis y de radiología, de empresas prestadoras de toda clase de servicios médicos, en cualquier parte de la república mexicana o en el extranjero. La prestación de servicios profesionales en territorio nacional o en el extranjero, por si o a través de terceros, a personas físicas y morales, empresas y corporaciones de índole privado, así como a instituciones públicas y gubernamentales, sean municipales, estatales o federales, nacionales y extranjeras; particularmente en la consultoría y asesoría en la administración y manejo de todo tipo de negociaciones en materia de procesos industriales, construcción, capacitación, recursos humanos, comercio, administración, dirección empresarial, desarrollo organizacional, fiscal, corporativo y mercadotecnia para negociaciones y empresas relacionadas con la actividad de la Sociedad.','Folio Mercantil Electrónico 95356*1 nueve, cinco, tres, cinco, seis, uno, del Registro Público de Comercio de Guadalajara, Jalisco','2026-02-05 00:37:41.118+00','completed',NULL,NULL,NULL,NULL,NULL,NULL,'[]','true',NULL,NULL,'{}',NULL,NULL,NULL,NULL,NULL);
