INSERT INTO public."documents" (id,supplier_id,document_type,file_url,file_name,status,version,notes,reviewed_by,reviewed_at,created_at,updated_at,razon_social,representante_legal,objeto_social,registro_publico,extracted_at,extraction_status,rfc,actividad_economica,regimen_tributario,fecha_emision,codigo_postal,direccion,validation_errors,is_valid,nombre_completo_ine,curp,image_urls,numero_cuenta,numero_cuenta_clabe,nombre_cliente,nombre_banco,regimen_fiscal) VALUES ('2eb5d681-1792-444d-9898-3e42719d2bbe','3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b','acta_constitutiva','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0.pdf','1- Acta constitutiva Escritura 18,127  INICIAL.pdf','aprobado','1',NULL,'989165e0-c24f-4360-a1dc-1b84536947b5','2026-04-13 18:10:09.814+00','2026-02-26 00:48:15.11929+00','2026-04-13 18:10:09.828942+00','PROBEMEDIC DISTRIBUCIONES, S.A. DE C.V.','Gerardo Alberto Martínez Robledo','a).- Compra, venta, distribución y comercialización de productos farmacéuticos.\nb).- Comprar, vender, distribuir, arrendar o dar en comodato; por cuenta propia o de terceros, medicamentos, medicinas, equipo medico, equipo de curación, material de curación, consumibles médicos y hospitalarios entre otros.\nc).- La prestación y obtención de servicios de cualquier índole de toda clase de empresas de carácter comercial e industrial, así como toda clase de personas físicas o morales.\nd).- Celebrar toda clase de contratos con personas físicas o morales para administrar u operar, empresas, o celebrar convenios que tengan relación con su objeto social, con empresas industriales o comerciales.\ne).- La adquisición y venta por cualquier medio legal de toda clase de bienes muebles e inmuebles para la realización de su objeto social, dar y tomar en arrendamiento bienes muebles e inmuebles.\nf).- La adquisición y venta de acciones partes de interés, participaciones en sociedades o empresas relacionadas con los fines expresados, así como obligaciones o bonos y la emisión de obligaciones o bonos.\ng).- El otorgar activa o pasivamente toda clase de garantías reales o personales en asuntos que la sociedad y los socios consideren de interés para la misma.\nh).- Organización de publicidad y campañas publicitarias y de propaganda por todos los medios que se estimen convenientes.\ni).- Suscribir, tramitar permisos para adquirir, poseer, para usar y enajenar marcas, patentes, nombres comerciales, invenciones que se relacionen con los objetos de la Sociedad.\nj).- Realizar toda y cualquier actividad relacionada con el desarrollo e investigación de tecnología, promover, conocer y realizar todo evento relacionado con la asistencia técnica, realizar toda y cualquier actividad encaminada a los objetos de la Sociedad.\nk).- la compra, venta, emisión, giro, aceptación, aval o de los títulos o valores y en general la realización de cualesquiera operaciones permitidas con valores y títulos de crédito en general, de cualquier índole, que no estén reservados expresamente a las Instituciones de crédito, así como constituirse como Aval, deudor y/o obligado solidario.\nl).- Promover, conocer y realizar todo evento relacionado con la asistencia técnica así como de cualquier actividad encaminada a los objetos de la Sociedad.\nm).- En general, la celebración de toda clase de contratos, la ejecución de actos y la realización de operaciones civiles, mercantiles o financieras, que directamente se relacionen, deriven, sean consecuencia o convenientes para los objetos indicados, para sí, por cuenta de terceros o en participación y que legalmente sean compatibles en razón de su capacidad.\nn).- La prestación a personas morales o físicas de toda clase de servicios y asesorías en general, ya sean por sí o a través de terceros por cuenta propia o ajena, especialmente los relacionados o sean conexos o similares a los fines de la sociedad.\no).- La aceptación y otorgamiento de concesiones y franquicias, así como el registro, obtención, uso, traspaso, cesión y autorización de uso, según el caso, de marcas, patentes de invención y de mejoras, diseños o modelos relacionados en lo general con el objeto social de la Sociedad.','Escritura Pública Número 18,127, Folio No. 026472, de fecha 15 de marzo de 2011, Notaría Pública Número 84 en Monterrey, Nuevo León, a cargo del Licenciado Enrique J. Kuri Gallardo.','2026-02-26 00:49:24.547+00','completed',NULL,NULL,NULL,NULL,NULL,NULL,'[]','true',NULL,NULL,'{3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_1.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_2.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_3.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_4.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_5.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_6.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_7.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_8.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_9.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_10.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_11.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_12.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_13.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_14.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_15.png,3fee6c23-ccb4-4f1f-b73e-c7f59ed44e2b/1772066892864_0_page_16.png}',NULL,NULL,NULL,NULL,NULL);
