INSERT INTO public."documents" (id,supplier_id,document_type,file_url,file_name,status,version,notes,reviewed_by,reviewed_at,created_at,updated_at,razon_social,representante_legal,objeto_social,registro_publico,extracted_at,extraction_status,rfc,actividad_economica,regimen_tributario,fecha_emision,codigo_postal,direccion,validation_errors,is_valid,nombre_completo_ine,curp,image_urls,numero_cuenta,numero_cuenta_clabe,nombre_cliente,nombre_banco,regimen_fiscal) VALUES ('3f2f7705-62ac-4214-a572-a2255e81facd','4912b75c-1c11-4406-b22e-8bc72ee4dc79','acta_constitutiva','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0.pdf','ACTA CONSTITUTIVA HDL.pdf','aprobado','1',NULL,'989165e0-c24f-4360-a1dc-1b84536947b5','2026-04-13 17:34:05.292+00','2026-03-18 17:28:32.755591+00','2026-04-13 17:34:05.416752+00','COMERCIALIZADORA FARMACEUTICA HDL, S.A. DE C.V.','JESÚS RICARDO HURTADO DE LEÓN','El objeto social se enfoca en diversas actividades relacionadas con el ámbito farmacéutico, incluyendo pero no limitándose a: compraventa de bienes muebles e inmuebles; prestación de servicios de consultoría, asesoría y gestoría; participación en licitaciones y concursos para diversos niveles de gobierno; celebración de contratos y convenios de todo tipo; constitución de sociedades mercantiles y civiles; importación y exportación de productos; adquirir y enajenar bienes muebles e inmuebles; otorgar fianzas, avales o cualquier otra garantía; adquirir y suscribir títulos de crédito; ejecutar actos de comercio y los necesarios para cumplir su objeto.','REGISTRO PÚBLICO DE LA PROPIEDAD Y DEL COMERCIO DE LEÓN, GUANAJUATO. BOLETA DE INSCRIPCIÓN No. 64511 * 20. Control Interno: 1 * 06 / DICIEMBRE / 2013. Tipo de Movimiento: M4. Descripción: Constitución de sociedad. Número de Pre-Alerta: 4a9ef993f29298ea3f5d35fef149c9234d61701. Derechos de Inscripción: 06/12/2013. Fecha: 06/12/2013. Importe: $1,000.00. Boleta de pago No.: 008017543469.','2026-03-18 17:30:09.424+00','completed',NULL,NULL,NULL,NULL,NULL,NULL,'[]','true',NULL,NULL,'{4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_1.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_2.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_3.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_4.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_5.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_6.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_7.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_8.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_9.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_10.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_11.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_12.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_13.png,4912b75c-1c11-4406-b22e-8bc72ee4dc79/1773854911516_0_page_14.png}',NULL,NULL,NULL,NULL,NULL);
