INSERT INTO public."documents" (id,supplier_id,document_type,file_url,file_name,status,version,notes,reviewed_by,reviewed_at,created_at,updated_at,razon_social,representante_legal,objeto_social,registro_publico,extracted_at,extraction_status,rfc,actividad_economica,regimen_tributario,fecha_emision,codigo_postal,direccion,validation_errors,is_valid,nombre_completo_ine,curp,image_urls,numero_cuenta,numero_cuenta_clabe,nombre_cliente,nombre_banco,regimen_fiscal) VALUES ('06ddf3b9-7267-43ed-a208-afd7aa3e04fa','2201f30a-8ecc-4674-896d-31257044dfc7','acta_constitutiva','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0.pdf','ACTA CONSTITUTIVA FARMACEUTICAS LEAL (1).pdf','aprobado','1',NULL,'989165e0-c24f-4360-a1dc-1b84536947b5','2026-04-13 18:00:42.468+00','2026-03-09 16:11:54.82421+00','2026-04-13 18:00:42.374214+00','FARMACÉUTICAS LEAL, S.A. DE C.V.','ROCIO MIROSLAVA GUZMAN MUÑOZ y MARTIN ALEJANDRO LEAL JARAMILLO','La compra, venta, comercialización, distribución, mediación, intermediación, administración, representación, consignación, colocación, transportación, importación, exportación y/o enajenación al por mayor o al por menor en el mercado nacional y/o en el extranjero, de todo tipo de productos de los ramos de medicina, Darse, droguería, alimentos, bebidas Puras, artículos de higiene personal, línea blanca, artículos eléctricos y electrónicos, regalos, accesorios, juguetería, fotografía, artículos de limpieza y cualquier otro permitido por las leyes. --II) Comprar, vender, producir, fabricar, importar, exportar, comercializar, distribuir y representar en mercados nacionales o extranjeros, respecto de todo tipo de preparaciones y productos farmacéuticos, químicos, biológicos, médicos, sueros, vacunas, aparatos de cirugía, así como toda clase de productos y equipos para hospitales. Así como vender medicamentos al mayoreo y/o menudeo. --III) La realización de cualquier actividad relacionada y/o la comercialización, mediación, intermediación, administración, comisión, colocación, transportación, importación, exportación y/o enajenación de manera electrónica o a través de cualquier medio, de toda clase de productos.','PÓLIZA NÚMERO 24,210. LIBRO QUINTO DE REGISTRO. En la ciudad de Guadalajara, Jalisco, siendo el día 17 diecisiete de octubre del 2022 dos mil veintidós, ante mí, Licenciado FABIÁN TOMMASI MÉNDEZ, Corredor Público número 57 cincuenta y siete de la Plaza del Estado de Jalisco.','2026-03-09 16:14:10.287+00','completed',NULL,NULL,NULL,NULL,NULL,NULL,'[]','true',NULL,NULL,'{2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_1.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_2.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_3.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_4.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_5.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_6.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_7.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_8.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_9.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_10.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_11.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_12.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_13.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_14.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_15.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_16.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_17.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_18.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_19.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_20.png,2201f30a-8ecc-4674-896d-31257044dfc7/1773072707795_0_page_21.png,2201f30a-8ecc-4674-896d-31257044dfc7/177