INSERT INTO public."documents" (id,supplier_id,document_type,file_url,file_name,status,version,notes,reviewed_by,reviewed_at,created_at,updated_at,razon_social,representante_legal,objeto_social,registro_publico,extracted_at,extraction_status,rfc,actividad_economica,regimen_tributario,fecha_emision,codigo_postal,direccion,validation_errors,is_valid,nombre_completo_ine,curp,image_urls,numero_cuenta,numero_cuenta_clabe,nombre_cliente,nombre_banco,regimen_fiscal) VALUES ('383d54e3-daf5-4daa-85c3-2679ae900f06','1fafd7a9-0e01-4308-979d-2363b1bbc87f','acta_constitutiva','https://cjhmbqmhfbspgirnkjkm.supabase.co/storage/v1/object/public/documents/1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0.pdf','E.-ACTA CONSTITUTIVA.pdf','pendiente','1',NULL,NULL,NULL,'2026-04-15 19:23:58.38338+00','2026-04-15 19:25:57.379161+00','MACRO FARMACIAS, S.A. DE C.V.','Liliana Juvenal Echeverria Gallegos, Angelica Elizabeth Olea Alejandre','Celebrar toda clase de créditos, así como para para recibir pagos, hacer cesión de bienes, adquirir en venta o autoridad, formular posturas que procedan, respecto de los bienes que sean materia del juicio, facultad para pleitos y cobranzas, con todas las facultades generales y las que conforme a la ley requieran clausula especial, en los términos del primer párrafo del artículo 10 diez de la Ley General de Sociedades Mercantiles y en los términos del primer párrafo del artículo 2554 dos mil quinientos cincuenta y cuatro y el artículo 2587 dos mil quinientos ochenta y siete del Código Civil Federal incluye la facultad interponer y desistir de toda clase de procedimientos federales y locales, incluso el de amparo. Para transigir. Para comprometer en árbitros. Para absolver y articular posiciones. Para recurrir. Para recibir pagos. Para hacer cesión de bienes. Para adquirir en veta de autoridad formulando las posturas y pujas que procedan respecto de los bienes que sean materia del juicio. Para representar denuncias y querellas en materia penal y constituirse por su mandante en parte civil o en tercero coadyuvante del Ministerio Público. Así como para desistirse de los respectivos acciones e instancias cuando lo permita la ley y otorgar el perdón en su caso.','Póliza número 1,074, del 08 de noviembre de 2010, ante el Corredor Público No. 42 de la Plaza del Estado de Jalisco, Lic. Antonio Rodríguez López.','2026-04-15 19:25:57.212+00','completed',NULL,NULL,NULL,NULL,NULL,NULL,'[]','true',NULL,NULL,'{1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_1.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_2.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_3.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_4.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_5.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_6.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_7.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_8.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_9.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_10.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_11.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_12.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_13.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_14.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_15.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_16.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_17.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_18.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_19.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_20.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_21.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_22.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_23.png,1fafd7a9-0e01-4308-979d-2363b1bbc87f/1776281035481_0_page_24.